class Solution {
public:
    int maxStability(int n, vector<vector<int>>& edges, int k) {
        vector<vector<pair<int, int>>> graph(n);
        vector<int> parent(n);
        for (int i = 0; i < n; ++i) parent[i] = i;

        vector<pair<int, int>> must_edges;
        int total_must_edges = 0;

        for (auto& edge : edges) {
            int u = edge[0], v = edge[1], strength = edge[2], must = edge[3];
            if (must == 1) {
                must_edges.emplace_back(strength, u * n + v);
                total_must_edges++;
            }
        }

        sort(must_edges.begin(), must_edges.end());
        for (auto& edge : must_edges) {
            int u = edge.second / n, v = edge.second % n;
            if (!unionSet(u, v, parent)) return -1;
        }

        if (total_must_edges != n - 1) {
            for (auto& edge : edges) {
                int u = edge[0], v = edge[1], strength = edge[2], must = edge[3];
                if (must == 0) graph[u].emplace_back(v, strength);
                if (must == 0) graph[v].emplace_back(u, strength);
            }
        } else {
            for (auto& edge : edges) {
                int u = edge[0], v = edge[1], strength = edge[2], must = edge[3];
                if (findSet(u, parent) != findSet(v, parent) && must == 0) {
                    graph[u].emplace_back(v, strength);
                    graph[v].emplace_back(u, strength);
                }
            }
        }

        priority_queue<pair<int, int>> pq;
        for (int i = 0; i < n; ++i) {
            for (auto& neighbor : graph[i]) {
                pq.emplace(neighbor.second, i * n + neighbor.first);
            }
        }

        int low = 1, high = 1e5 + 1;
        while (low < high) {
            int mid = (low + high + 1) / 2;
            if (check(mid, k, pq, parent, n)) low = mid;
            else high = mid - 1;
        }
        return low;
    }

    bool check(int mid, int k, priority_queue<pair<int, int>>& pq, vector<int>& parent, int n) {
        vector<int> new_parent(n);
        for (int i = 0; i < n; ++i) new_parent[i] = i;
        int count = 0;
        priority_queue<pair<int, int>> temp = pq;
        while (!temp.empty()) {
            auto edge = temp.top();
            temp.pop();
            int u = edge.second / n, v = edge.second % n;
            if (edge.first >= mid && unionSet(u, v, new_parent)) count++;
            else if (edge.first * 2 >= mid && k > 0 && unionSet(u, v, new_parent)) {
                count++;
                k--;
            }
        }
        return count == n - 1;
    }

    int findSet(int x, vector<int>& parent) {
        if (parent[x] != x) parent[x] = findSet(parent[x], parent);
        return parent[x];
    }

    bool unionSet(int x, int y, vector<int>& parent) {
        int xs = findSet(x, parent), ys = findSet(y, parent);
        if (xs == ys) return false;
        parent[xs] = ys;
        return true;
    }
};
